create function cocoon_product_group_subtree(@root int)
returns table as
return
with group_(parent_id, id, text_)
as
(
select @root, IdObj, strNazwa from n5grupaproduktow where pGrupaNadrzedna = @root
union all 
select pGrupaNadrzedna, IdObj, strNazwa from n5grupaproduktow 
inner join group_ on pGrupaNadrzedna = id
)
select parent_id, id, text_ from group_
union all select 0, IdObj, strNazwa from n5grupaproduktow where IdObj=@root
GO
SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON
create function dbo.nx_div( @curlicz_par decimal(14,4),@curmian_par decimal(14,4))
returns decimal(14,4)
as
begin
declare @result decimal(14,4)
if @curmian_par = 0
select @result = 0
else
select @result = (@curlicz_par / @curmian_par)
return @result
end

GO
SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

create function dbo.sprzedaz_history(@idSprzedaz int)
returns table
as
return
(
	with sp_hist(idSprzed) as
	(
		select @idSprzedaz
		union all
		select idObj from n5sprzedaz join sp_hist on pPopSprzed = idSprzed
	)
	select idSprzed from sp_hist
)

GO
SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

create function dbo.sprzedaz_history_dokmag(@idDokMag int)
returns table
as
return
(
	with sp_hist(idSprzed) as
	(
		select wrefDokHandl from n5dokmag where wrefDokHandl_wrt=10129 and idobj=@idDokMag
		union all
		select idObj from n5sprzedaz join sp_hist on pPopSprzed = idSprzed
	)
	select idSprzed from sp_hist
)

GO

