inner join n5realprod rps on om.gmo_nNumOp = rps.nnumoper
where gmo_nnumop > (select isnull(Wartosc,0) from n5globprof where indeks=1086)
union all
select 
'nTypDok'=0,
'typeid'=0,
'idobjdok'=0,
'strNrDok'='ARCHIWUM',
