'vws_idWyrProd' = vlw.c_pprodukt, 'vws_idWyrOpak' = vlw.c_popak,
'vws_idSurProd' = vls.c_pprodukt, 'vws_idSurOpak' = vls.c_popak,
'vws_curLicz' = vls.c_curIloscOpak, 'vws_curMian' = vlw.c_curIloscOpak,
'vws_idRec' = vlw.p_idobj,'vws_strSurInx' = ps.strIndeks
from vlist_n5recepta_listwyrob vlw
join vlist_n5recepta_listsurowce vls on vlw.p_idobj=vls.p_idobj
and vlw.p_idobj = (select min(p_idobj) from vlist_n5recepta_listwyrob vlw2 where vlw2.c_pprodukt = vlw.c_pprodukt)
join n5produkt ps on vls.c_pprodukt = ps.idobj

