create procedure [dbo].[fill_arkusz_zapotrzebowania]
@mag_nazwa nvarchar(max),
@datawystod_param datetime,
@datawystdo_param datetime,
@rejestr_nazwa nvarchar(max),
@datawystod2_param datetime,
@datawystdo2_param datetime,
@datarealod_param datetime,
@datarealdo_param datetime,
@prod_grp_nazwy nvarchar(max)
as 

declare @grp_root_ids table (idobj INT)
declare @idmag_param int
declare @idrejsp_param int
declare @grp_sql nvarchar(max)
declare @idobj integer
declare @sub_cur cursor

if exists(select * from sys.sysobjects where name like '%king_ark_zap%')
drop table king_ark_zap

truncate table king_grp_ids

select @idmag_param = 0
select @idmag_param=idobj from n5magazyn where strnazwa=@mag_nazwa

select @idrejsp_param = 0
select @idrejsp_param=idobj from n5rejestrdok where strnazwa=@rejestr_nazwa

select @grp_sql = 'insert into king_grp_ids select idobj from n5grupaproduktow'
if @prod_grp_nazwy <> '' 
select @grp_sql = @grp_sql + ' where strNazwa ' +'IN (''' + REPLACE(REPLACE(@prod_grp_nazwy, '''' ,''''''), ',' ,''',''')  + ''')'

EXECUTE sp_executesql @grp_sql
insert into @grp_root_ids select idobj from king_grp_ids
truncate table king_grp_ids

set @sub_cur = cursor fast_forward for select idobj from @grp_root_ids
open @sub_cur
fetch next from @sub_cur into @idobj
while @@fetch_status = 0
begin
exec king_grp_subtree @idobj
fetch next from @sub_cur into @idobj
end
close @sub_cur
deallocate @sub_cur

select 
-- kontrolnie tylko:
'c_prod_first'=v_prod_opak.p_strNazwa,
-- 
'c_prod_id' = v_prod_opak.p_idobj,
'c_opak_id' = v_prod_opak.c_idobj,
'c_stan_mag' = (select isnull(sum(gms_curIlosc),0) 
 from n5gmstan 
 where gms_pProd = v_prod_opak.p_idobj and gms_pOpak = v_prod_opak.c_idobj and gms_pMag = @idmag_param),
'c_ilosc_zam_zak' = (select isnull(sum(c_curiloscopakpoz),0) 
 from vlist_n5zamowienie_listPozycje v_zam_zak
 where v_zam_zak.c_pprodukt = v_prod_opak.p_idobj and v_zam_zak.c_popak = v_prod_opak.c_idobj
 and v_zam_zak.p_prejestrdok in (select IdObj from n5rejestrdok where eTyp in (34))),
'c_stan_min' = v_prod_opak.c_curIloscMin,
'c_waga_netto' = v_prod_opak.c_curWagaNetto,
'c_prec'= t_jedn.nDokladnosc,
'c_ilosc_sprzed' = v_prod_opak.c_currKrotnosc *(select isnull(sum(v_sprzed.c_curIloscOpak - isnull(v_org_sprzed.c_curIloscOpak,0)),0)
from vlist_n5sprzedaz_listpozycje as v_sprzed
left outer join vlist_n5sprzedaz_listpozycje v_org_sprzed 
on v_sprzed.p_ppopsprzed = v_org_sprzed.p_idobj and v_sprzed.coll_lp = v_org_sprzed.coll_lp
where 
 v_sprzed.c_pprodukt = v_prod_opak.p_idobj and v_sprzed.c_popak = v_prod_opak.c_idobj
 and v_sprzed.p_dDataWyst between @datawystod_param and @datawystdo_param
),
'c_ilosc_sprzed_rej' = v_prod_opak.c_currKrotnosc *(select isnull(sum(v_sprzed.c_curIloscOpak - isnull(v_org_sprzed.c_curIloscOpak,0)),0)
from vlist_n5sprzedaz_listpozycje as v_sprzed
left outer join vlist_n5sprzedaz_listpozycje v_org_sprzed 
on v_sprzed.p_ppopsprzed = v_org_sprzed.p_idobj and v_sprzed.coll_lp = v_org_sprzed.coll_lp
where 
 v_sprzed.c_pprodukt = v_prod_opak.p_idobj and v_sprzed.c_popak = v_prod_opak.c_idobj
 and v_sprzed.p_dDataWyst between @datawystod_param and @datawystdo_param
 and v_sprzed.p_prejestrdok in (@idrejsp_param)
),
'c_ilosc_sred' = 0,
'c_ilosc_sprzed_2' = v_prod_opak.c_currKrotnosc *(select isnull(sum(v_sprzed.c_curIloscOpak - isnull(v_org_sprzed.c_curIloscOpak,0)),0)
from vlist_n5sprzedaz_listpozycje as v_sprzed
left outer join vlist_n5sprzedaz_listpozycje v_org_sprzed 
on v_sprzed.p_ppopsprzed = v_org_sprzed.p_idobj and v_sprzed.coll_lp = v_org_sprzed.coll_lp
where 
 v_sprzed.c_pprodukt = v_prod_opak.p_idobj and v_sprzed.c_popak = v_prod_opak.c_idobj
 and v_sprzed.p_dDataWyst between @datawystod2_param and @datawystdo2_param
),
'c_ilosc_zam_sp' = (select isnull(sum(c_curiloscopakpoz),0) 
 from vlist_n5zamowienie_listPozycje v_zam_sprzed
 where v_zam_sprzed.c_pprodukt = v_prod_opak.p_idobj and v_zam_sprzed.c_popak = v_prod_opak.c_idobj
 and v_zam_sprzed.p_prejestrdok in (select IdObj from n5rejestrdok where eTyp in (33))
 and v_zam_sprzed.p_ddatareal  between @datarealod_param and @datarealdo_param),
'c_ost_zak_data' = isnull(v_last_zakup.p_ddatazakupu,{d '2010-01-01'}),
'c_ost_zak_dost_id' = isnull(v_last_zakup.p_pDostawca,0),
'c_ost_zak_cena'= isnull(v_last_zakup.c_curcenanettowal,0),
'c_opak_zbior_nazwa'=(select isnull(max(v_prod_opak_2.c_strnazwa),'')
 from vlist_n5produkt_listOpakowania v_prod_opak_2 
 where v_prod_opak_2.p_idobj = v_prod_opak.p_idobj and c_erodzaj=2),
'c_opak_zbior_krotnosc'=(select isnull(max(v_prod_opak_2.c_currkrotnosc),0)
 from vlist_n5produkt_listOpakowania v_prod_opak_2 
 where v_prod_opak_2.p_idobj = v_prod_opak.p_idobj and c_erodzaj=2)
 into king_ark_zap
from vlist_n5produkt_listOpakowania v_prod_opak
inner join n5jednostka as t_jedn on v_prod_opak.c_pJednOpak = t_jedn.IdObj
left outer join vlist_n5zakup_listPozycje v_last_zakup on v_last_zakup.c_idobj = 
(select top 1 v_zakup.c_idobj from vlist_n5zakup_listPozycje v_zakup 
where v_zakup.c_pprodukt = v_prod_opak.p_idobj and v_zakup.c_popak = v_prod_opak.c_idobj
order by v_zakup.p_ddatazakupu desc)
where v_prod_opak.coll_lp=1 and v_prod_opak.p_pgrupaprod in (select idobj from king_grp_ids)


GO
