create procedure king_grp_subtree(@idroot integer)
as
declare @idobj integer
declare @sub_cur cursor
set @sub_cur = cursor fast_forward for select idobj from n5grupaproduktow where pGrupaNadrzedna=@idroot
insert into king_grp_ids values(@idroot)
