create procedure n5klient_obiekt_candel(@idobj_par integer) with encryption as 
select TOP 5 'typeid'=cast(10132 as integer),idobj from n5pozsprzedaz where psprzed_pKLOB=@idobj_par
union
select TOP 5 'typeid'=cast(10149 as integer),idobj from n5egzemplarz where egze_pKlientObiekt=@idobj_par
union
select TOP 5 'typeid'=cast(10162 as integer),idobj from n5dokmag where pObiektKlienta=@idobj_par
union
select TOP 5 'typeid'=cast(10119 as integer),idobj from n5zadanie where zad_pKLOB=@idobj_par
union
select TOP 5 'typeid'=cast(10238 as integer),idobj from n5pozdokprod where pdp_pKLOB=@idobj_par
union
select TOP 5 'typeid'=cast(10161 as integer),idobj from n5pozdokmag where pdm_pObiektKlienta=@idobj_par
union
select TOP 5 'typeid'=cast(10175 as integer),idobj from n5pozzakup where pzak_pObiektKlienta=@idobj_par
go

