union
select TOP 5 'typeid'=cast(10221 as integer),idobj from n5plpozostale where pPracownik=@idobj_par
union
select TOP 5 'typeid'=cast(10116 as integer),idobj from n5grupaproduktow where grp_pPracownik=@idobj_par
