create procedure n5kraj_candel(@idobj_par integer) with encryption as 
select TOP 5 'typeid'=cast(10234 as integer),idobj from n5klient_obiekt where klob_pKraj=@idobj_par
union
select TOP 5 'typeid'=cast(10129 as integer),idobj from n5sprzedaz where sprzed_pKraj_dost=@idobj_par
union
select TOP 5 'typeid'=cast(10109 as integer),idobj from n5pracownik where pKraj=@idobj_par
union
select TOP 5 'typeid'=cast(10109 as integer),idobj from n5pracownik where pprac_Kraj_zameld=@idobj_par
union
select TOP 5 'typeid'=cast(10109 as integer),idobj from n5pracownik where pprac_Kraj_koresp=@idobj_par
union
select TOP 5 'typeid'=cast(10242 as integer),idobj from n5projekt_abas where proj_pKraj=@idobj_par
union
select TOP 5 'typeid'=cast(10100 as integer),idobj from n5wojewodztwo where pKraj=@idobj_par
union
select TOP 5 'typeid'=cast(10114 as integer),idobj from n5_klient_jedn_org where pKraj=@idobj_par
union
select TOP 5 'typeid'=cast(10131 as integer),idobj from n5produkt where prod_pKrajPoch=@idobj_par
union
select TOP 5 'typeid'=cast(10162 as integer),idobj from n5dokmag where dm_pKraj_dost=@idobj_par
union
select TOP 5 'typeid'=cast(10108 as integer),idobj from n5klient where pKraj=@idobj_par
union
select TOP 5 'typeid'=cast(10108 as integer),idobj from n5klient where pKrajSDB=@idobj_par
union
select TOP 5 'typeid'=cast(10105 as integer),idobj from n5instytucja where pKraj=@idobj_par
union
select TOP 5 'typeid'=cast(10113 as integer),idobj from n5jedn_org where pKraj=@idobj_par
union
select TOP 5 'typeid'=cast(10110 as integer),idobj from n5firma where pKraj=@idobj_par
union
select TOP 5 'typeid'=cast(10104 as integer),idobj from n5bank where pKraj=@idobj_par
union
select TOP 5 'typeid'=cast(10172 as integer),idobj from n5zamowienie where zam_pKraj_dost=@idobj_par
go

