create procedure n5miejscowosc_candel(@idobj_par integer) with encryption as 
select TOP 5 'typeid'=cast(10234 as integer),idobj from n5klient_obiekt where klob_pMiejscowosc=@idobj_par
union
select TOP 5 'typeid'=cast(10129 as integer),idobj from n5sprzedaz where sprzed_pMiejscowosc_dost=@idobj_par
union
select TOP 5 'typeid'=cast(10109 as integer),idobj from n5pracownik where pMiejscowosc=@idobj_par
union
select TOP 5 'typeid'=cast(10109 as integer),idobj from n5pracownik where pprac_Miejscowosc_zameld=@idobj_par
union
select TOP 5 'typeid'=cast(10109 as integer),idobj from n5pracownik where pprac_Miejscowosc_koresp=@idobj_par
union
select TOP 5 'typeid'=cast(10242 as integer),idobj from n5projekt_abas where proj_pMiejscowosc=@idobj_par
union
select TOP 5 'typeid'=cast(10114 as integer),idobj from n5_klient_jedn_org where pMiejscowosc=@idobj_par
union
select TOP 5 'typeid'=cast(10284 as integer),idobj from n5poz_koszt_wyjazdu where pdkw_pMiejscowoscWy=@idobj_par
union
select TOP 5 'typeid'=cast(10284 as integer),idobj from n5poz_koszt_wyjazdu where pdkw_pMiejscowoscPrzy=@idobj_par
union
select TOP 5 'typeid'=cast(10162 as integer),idobj from n5dokmag where dm_pMiejscowosc_dost=@idobj_par
union
select TOP 5 'typeid'=cast(10108 as integer),idobj from n5klient where pMiejscowosc=@idobj_par
union
select TOP 5 'typeid'=cast(10108 as integer),idobj from n5klient where pMiejscowoscSDB=@idobj_par
union
select TOP 5 'typeid'=cast(10105 as integer),idobj from n5instytucja where pMiejscowosc=@idobj_par
union
select TOP 5 'typeid'=cast(10113 as integer),idobj from n5jedn_org where pMiejscowosc=@idobj_par
union
select TOP 5 'typeid'=cast(10110 as integer),idobj from n5firma where pMiejscowosc=@idobj_par
union
select TOP 5 'typeid'=cast(10104 as integer),idobj from n5bank where pMiejscowosc=@idobj_par
union
select TOP 5 'typeid'=cast(10172 as integer),idobj from n5zamowienie where zam_pMiejscowosc_dost=@idobj_par
go

