create procedure n5pit5_delete(@idobj_par integer) with encryption as 
	delete from n5pit5 where idobj=@idobj_par
return @@rowcount
go

create procedure n5pit5_maxid(@maxid_par integer output) with encryption as 
	select @maxid_par=max(idobj) from n5pit5
go

create procedure n5pit5_candel(@idobj_par integer) with encryption as 
select TOP 5 'typeid'=cast(10148 as integer),idobj from n5dowodksieg where wrefDokZrod=@idobj_par and wrefDokZrod_wrt=10136
go

