create procedure n5opakowanie_produktu_candel(@idobj_par integer) with encryption as 
select TOP 5 'typeid'=cast(10132 as integer),idobj from n5pozsprzedaz where pOpak=@idobj_par
union
select TOP 5 'typeid'=cast(10132 as integer),idobj from n5pozsprzedaz where pOpakOrg=@idobj_par
union
select TOP 5 'typeid'=cast(10149 as integer),idobj from n5egzemplarz where egze_pOpak=@idobj_par
