create procedure n5plnaliczenie_candel(@idobj_par integer) with encryption as 
select TOP 5 'typeid'=cast(10134 as integer),idobj from n5pkpir where pkpir_wrefDokZrodl=@idobj_par and pkpir_wrefDokZrodl_wrt=10192
union
select TOP 5 'typeid'=cast(10148 as integer),idobj from n5dowodksieg where wrefDokZrod=@idobj_par and wrefDokZrod_wrt=10192
union
select TOP 5 'typeid'=cast(10119 as integer),idobj from n5zadanie where wrefSzczegoly=@idobj_par and wrefSzczegoly_wrt=10192
union
select TOP 5 'typeid'=cast(10252 as integer),idobj from n5transakcja_operacja where trop_wrefDokument=@idobj_par and trop_wrefDokument_wrt=10192
go

