create procedure n5pit11_delete(@idobj_par integer) with encryption as 
	delete from n5pit11 where idobj=@idobj_par
return @@rowcount
go

create procedure n5pit11_maxid(@maxid_par integer output) with encryption as 
	select @maxid_par=max(idobj) from n5pit11
go

create procedure n5pit11_candel(@idobj_par integer) with encryption as 
select TOP 5 'typeid'=cast(10148 as integer),idobj from n5dowodksieg where wrefDokZrod=@idobj_par and wrefDokZrod_wrt=10138
go

