	@strNazwa_par=strNazwa,
	@pRejestrDok_par=pRejestrDok,
	@pDziennik_par=pDziennik,
	@strOpis_par=strOpis,
	@strVBcode_par=strVBcode,
	@eAktywny_par=eAktywny from n5schematdekr where IdObj=@idobj_par
